1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (wasAlive: boolean, liveNeighbors: number): boolean =>
12	  liveNeighbors === 3 || (wasAlive && liveNeighbors === 2);
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const aliveKeys = new Set(cells.map(keyOf));
16	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
17	
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const neighbor: Cell = [x + dx, y + dy];
21	      const k = keyOf(neighbor);
22	      const entry = neighborCounts.get(k);
23	      if (entry) entry.count++;
24	      else neighborCounts.set(k, { cell: neighbor, count: 1 });
25	    }
26	  }
27	
28	  return [...neighborCounts]
29	    .filter(([k, { count }]) => survives(aliveKeys.has(k), count))
30	    .map(([, { cell }]) => cell);
31	}
32

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("single cell dies — [(0,0)] → []", () => {
6	    expect(nextGeneration([[0, 0]])).toEqual([]);
7	  });
8	  it("Rule 1 Underpopulation: two adjacent cells both die — [(0,1), (1,1)] → []", () => {
9	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
10	  });
11	  it.todo("Rule 4 Reproduction: dead cell with exactly 3 live neighbors becomes alive — [(0,2), (1,2), (0,1)] → [(0,2), (1,2), (0,1), (1,1)]");
12	  it.todo("Rule 2 Survival: center cell with 3 live neighbors survives (row + cell below) — center (1,1) stays alive");
13	  it.todo("Rule 3 Overpopulation: center cell with 4+ live neighbors dies — center (1,1) of full 3x3 minus middle becomes dead");
14	  it("Block still life: 2x2 block remains unchanged — [(0,0),(1,0),(0,1),(1,1)] stays the same", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("Blinker oscillator: vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(expected.sort());
24	  });
25	  it.todo("supports negative coordinates — blinker centered at origin oscillates correctly");
26	});
